import csv
from collections import defaultdict

rev = defaultdict(float)
with open('orders.csv', newline='') as f:
    for row in csv.DictReader(f):
        if row['status'] == 'shipped':
            rev[row['customer']] += float(row['qty']) * float(row['price_each'])

customer, revenue = max(rev.items(), key=lambda kv: kv[1])

def fmt(x):
    return str(int(round(x))) if abs(x-round(x)) < 1e-9 else ('%.10f' % x).rstrip('0').rstrip('.')

print("SIB_SUBMIT")
print(f"{customer}, {fmt(revenue)}")
